!read state subroutine for kr_rosco_types_controlparameters 
RECURSIVE SUBROUTINE kr_rosco_types_controlparameters(var, kgen_unit, printname, printvar) 
    TYPE(controlparameters), INTENT(INOUT) :: var 
    INTEGER, INTENT(IN) :: kgen_unit 
    CHARACTER(LEN=*), INTENT(IN) :: printname 
    LOGICAL, INTENT(IN), OPTIONAL :: printvar 
    LOGICAL :: kgen_istrue 
    REAL(KIND=8) :: kgen_array_sum 
      
    READ (UNIT = kgen_unit) var%zmq_id 
    IF (PRESENT( printvar ) .AND. printvar) THEN 
        WRITE (*, *) "KGEN DEBUG: " // printname // "%zmq_id = ", var%zmq_id 
    END IF   
      
    READ (UNIT = kgen_unit) var%logginglevel 
    IF (PRESENT( printvar ) .AND. printvar) THEN 
        WRITE (*, *) "KGEN DEBUG: " // printname // "%logginglevel = ", var%logginglevel 
    END IF   
      
    READ (UNIT = kgen_unit) var%echo 
    IF (PRESENT( printvar ) .AND. printvar) THEN 
        WRITE (*, *) "KGEN DEBUG: " // printname // "%echo = ", var%echo 
    END IF   
      
    READ (UNIT = kgen_unit) var%ext_interface 
    IF (PRESENT( printvar ) .AND. printvar) THEN 
        WRITE (*, *) "KGEN DEBUG: " // printname // "%ext_interface = ", var%ext_interface 
    END IF   
      
    READ (UNIT = kgen_unit) var%dt_out 
    IF (PRESENT( printvar ) .AND. printvar) THEN 
        WRITE (*, *) "KGEN DEBUG: " // printname // "%dt_out = ", var%dt_out 
    END IF   
      
    READ (UNIT = kgen_unit) var%n_dt_out 
    IF (PRESENT( printvar ) .AND. printvar) THEN 
        WRITE (*, *) "KGEN DEBUG: " // printname // "%n_dt_out = ", var%n_dt_out 
    END IF   
      
    READ (UNIT = kgen_unit) var%n_dt_zmq 
    IF (PRESENT( printvar ) .AND. printvar) THEN 
        WRITE (*, *) "KGEN DEBUG: " // printname // "%n_dt_zmq = ", var%n_dt_zmq 
    END IF   
      
    READ (UNIT = kgen_unit) var%f_lpftype 
